// v4.4: Updated eval prompt with evidence-based CS readiness (aligned with v9.8)
const c = $json;
const agingNote = c.is_aging_flag ? ' Company is ' + c.company_age + ' years old (aging flag).' : '';
const evalPrompt = 'COMPANY: ' + c.company_name + '. URL: ' + c.company_url + '. Description: ' + c.description + '. Funding: ' + (c.funding_stage || 'Unknown') + '. Employees: ' + (c.employee_count || 'Unknown') + '. Founded: ' + (c.founded_year || 'Unknown') + '. Persona: ' + c.customer_persona + '.' + agingNote + ' Score 0-100 for job search fit (VP/Head of Customer Support/Success). IMPORTANT for cs_readiness_score: Only cite evidence found in the sourced data. If no evidence of CS team building, score 0 and state "No evidence of CS build need found." Do NOT infer CS need from funding stage alone. Return JSON: {"bucket":"APPLY|WATCH|PASS","total_score":N,"sector_match":"target|adjacent|unrelated","cs_hire_likelihood":"high|medium|low","product_type":"enterprise|mid-market|self-serve","domain_distance":"target|adjacent|high-distance","domain_distance_modifier":N,"gtm_motion":"enterprise|plg|hybrid","role_type":"builder|maintainer|mixed","cs_readiness_score":N,"cs_readiness_reasoning":"evidence-based explanation","summary":"2 sentences"}. For domain_distance_modifier: target domains like healthcare B2B SaaS get +3 to +5, adjacent domains get 0, high-distance domains like ITSM/Legal/RealEstate get -5 to -10.';

return {
  json: {
    RECORD_ID: c.RECORD_ID,
    company_name: c.company_name,
    funding_stage: c.funding_stage,
    total_funding: c.total_funding,
    employee_count: c.employee_count,
    pe_backed: c.pe_backed,
    founded_year: c.founded_year,
    customer_persona: c.customer_persona,
    evalPrompt: evalPrompt
  }
};

const prev = $('Build Eval').first().json;
const RECORD_ID = prev.RECORD_ID;

const response = $json;
let evaluation = { bucket: 'WATCH', total_score: 0, summary: 'Parse error' };
try {
  const content = response.content?.[0]?.text || '';
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) evaluation = JSON.parse(jsonMatch[0]);
} catch (e) {}

// v4.2: Updated status mapping (removed Skip, use Passed)
const statusMap = { 'APPLY': 'Apply', 'WATCH': 'Monitor', 'PASS': 'Passed' };

// Valid Airtable select options
const validDomainDistance = ['target', 'adjacent', 'high-distance'];
const validGtmMotion = ['enterprise', 'plg', 'hybrid'];
const validRoleType = ['builder', 'maintainer', 'mixed'];
const validSectorMatch = ['target', 'adjacent', 'unrelated'];
const validCsHire = ['high', 'medium', 'low'];
const validProductType = ['enterprise', 'mid-market', 'self-serve'];
const validPersona = ['business-user', 'developer', 'employee-user', 'mixed'];

// Build fields object conditionally (omit select fields if invalid)
const fields = {
  'Status': statusMap[evaluation.bucket] || 'Research',
  'Tide-Pool Score': evaluation.total_score || 0,
  'Summary': evaluation.summary || '',
  'Stage': prev.funding_stage || '',
  'Total Funding': prev.total_funding || '',
  'Employee Count': prev.employee_count || null,
  'PE Backed': prev.pe_backed || false,
  'Founded Year': prev.founded_year || null,
  'Domain Distance Modifier': evaluation.domain_distance_modifier || 0,
  'CS Readiness Score': evaluation.cs_readiness_score || null
};

// Only add select fields if they have valid values
if (validSectorMatch.includes(evaluation.sector_match)) fields['Sector Match'] = evaluation.sector_match;
if (validCsHire.includes(evaluation.cs_hire_likelihood)) fields['CS Hire Likelihood'] = evaluation.cs_hire_likelihood;
if (validProductType.includes(evaluation.product_type)) fields['Product Type'] = evaluation.product_type;
if (validPersona.includes(prev.customer_persona)) fields['Customer Persona'] = prev.customer_persona;
if (validDomainDistance.includes(evaluation.domain_distance)) fields['Domain Distance'] = evaluation.domain_distance;
if (validGtmMotion.includes(evaluation.gtm_motion)) fields['GTM Motion'] = evaluation.gtm_motion;
if (validRoleType.includes(evaluation.role_type)) fields['Role Type'] = evaluation.role_type;

return {
  json: {
    RECORD_ID: RECORD_ID,
    company_name: prev.company_name,
    airtableFields: fields
  }
};
